import{_ as e}from"./chunks/api-keys.CiKfnKaq.js";import{_ as o}from"./chunks/create-key.HFKpZi27.js";import{_ as d,o as r,c as a,a2 as s}from"./chunks/framework.BflysNKA.js";const c="/images/tutorial/create-key.gif",i="/images/tutorial/create-key-result.png",k=JSON.parse('{"title":"创建专属 Key","description":"","frontmatter":{},"headers":[],"relativePath":"guide/create-key.md","filePath":"guide/create-key.md","lastUpdated":1780487298000}'),n={name:"guide/create-key.md"};function l(p,t,h,g,u,y){return r(),a("div",null,[...t[0]||(t[0]=[s('<h1 id="创建专属-key" tabindex="-1">创建专属 Key <a class="header-anchor" href="#创建专属-key" aria-label="Permalink to &quot;创建专属 Key&quot;">​</a></h1><p>Key（API 密钥）是工具调用 小蓝中转站 的凭证。建议<strong>按工具/设备分开创建</strong>（如 <code>Mac-ClaudeCode</code>、<code>Win-Codex</code>），这样方便分别查看消耗，万一某把泄露也只需删那一把。</p><blockquote><p>下面这张动图是完整流程，看不清的步骤再往下看分解说明。</p></blockquote><p><img src="'+c+'" alt="创建 Key 流程动图：打开 API 密钥页 → 创建 → 填名称/分组/额度 → 保存 → 复制新 Key"></p><h2 id="第-1-步-进入-api-密钥页面" tabindex="-1">第 1 步：进入 API 密钥页面 <a class="header-anchor" href="#第-1-步-进入-api-密钥页面" aria-label="Permalink to &quot;第 1 步：进入 API 密钥页面&quot;">​</a></h2><p>登录控制台后，点左侧导航栏的 <strong>API 密钥</strong>。第一次进来列表是空的：</p><p><img src="'+e+'" alt="API 密钥页面空状态：点左上角蓝色「创建 API 密钥」按钮新建"></p><p>点左上角蓝色的 <strong>创建 API 密钥</strong> 按钮（图中 ①）。</p><div class="tip custom-block"><p class="custom-block-title">接口地址</p><p>工具栏里的「接口地址」请<strong>以官网为准</strong>：OpenAI 兼容工具用 <code>https://xiaolan1.cn/v1</code>，Claude Code / Gemini CLI / Cherry Studio 用 <code>https://xiaolan1.cn</code>（不带 <code>/v1</code>）。详见 <a href="/guide/quick-start">快速接入</a>。</p></div><h2 id="第-2-步-填写表单" tabindex="-1">第 2 步：填写表单 <a class="header-anchor" href="#第-2-步-填写表单" aria-label="Permalink to &quot;第 2 步：填写表单&quot;">​</a></h2><p>点击后，左侧会滑出创建表单。按编号填即可，<strong>新手只需关注 ①②④ 三项</strong>，其余保持默认：</p><p><img src="'+o+'" alt="创建 API 密钥表单：① 名称、② 分组 auto、③ 过期时间、④ 无限配额、最后点保存修改"></p><table tabindex="0"><thead><tr><th>编号</th><th>字段</th><th>怎么填</th><th>说明</th></tr></thead><tbody><tr><td>①</td><td><strong>名称</strong></td><td><code>Mac-ClaudeCode</code> 或 <code>Win-Codex</code></td><td>建议用 <code>设备-工具</code> 格式，方便区分消耗。</td></tr><tr><td>②</td><td><strong>分组</strong></td><td>保持 <code>auto</code>（自动分组）</td><td>第一次接入先用 auto，跑通后再按需调整。</td></tr><tr><td>—</td><td><strong>跨分组重试</strong></td><td>保持开启</td><td>当前分组的渠道失败时，自动按顺序尝试下一个分组。</td></tr><tr><td>③</td><td><strong>过期时间</strong></td><td>保持「永不过期」</td><td>也可点 <code>1 个月</code>/<code>1 天</code>/<code>1 小时</code> 做临时测试。</td></tr><tr><td>—</td><td><strong>数量</strong></td><td><code>1</code></td><td>一次最多可批量创建多把（名称会自动加随机后缀）。</td></tr><tr><td>④</td><td><strong>无限配额</strong></td><td>先开着</td><td>新手先不要限制额度，跑通后再收紧。</td></tr></tbody></table><p>填好后点右下角 <strong>保存修改</strong>。</p><h2 id="第-3-步-立即复制并保存-key" tabindex="-1">第 3 步：立即复制并保存 Key <a class="header-anchor" href="#第-3-步-立即复制并保存-key" aria-label="Permalink to &quot;第 3 步：立即复制并保存 Key&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">完整 Key 只能复制这一次</p><p>保存后<strong>不会弹窗显示完整 Key</strong>，而是直接在列表里新增一行。把鼠标移到 <strong>API 密钥</strong> 这一列，会出现复制按钮，点它复制<strong>完整 Key</strong>。一旦离开，列表就只显示前后几位（如 <code>sk-x6of**********Ygw8</code>），中间永远不再展示。所以请马上把它粘贴到密码管理器或本地安全的地方。</p></div><p><img src="'+i+'" alt="创建成功：新 Key 出现在列表里，鼠标移到「API 密钥」列点复制按钮即可复制完整 Key"></p><p>完整 Key 是 <code>sk-</code> 开头的一串字符。后续配置工具时，把它填到各工具的 <strong>API Key</strong> 字段里。</p><h2 id="分组怎么选" tabindex="-1">分组怎么选 <a class="header-anchor" href="#分组怎么选" aria-label="Permalink to &quot;分组怎么选&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>建议</th></tr></thead><tbody><tr><td>第一次接入</td><td><code>auto</code>（自动分组），最省心</td></tr><tr><td>日常使用</td><td>默认分组或自己常用的分组</td></tr><tr><td>不确定</td><td>先用 <code>auto</code>，跑通后再调整</td></tr></tbody></table><h2 id="key-额度-vs-账号余额" tabindex="-1">Key 额度 vs 账号余额 <a class="header-anchor" href="#key-额度-vs-账号余额" aria-label="Permalink to &quot;Key 额度 vs 账号余额&quot;">​</a></h2><p>这两个是不同的东西，<strong>两边都要够，请求才能通过</strong>：</p><ul><li><strong>账号余额</strong>：钱包里的钱（充值得来），是真正扣费的来源。</li><li><strong>Key 额度</strong>：这把 Key 最多允许花多少。开了「无限配额」就只受账号余额限制。</li></ul><p>新手先开 <strong>无限配额</strong>，把流程跑通后再按需收紧。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>还没有余额？去 <a href="/guide/recharge">充值</a></li><li>需要模型名？去 <a href="https://xiaolan1.cn/pricing" target="_blank" rel="noreferrer">模型广场</a> 点模型名复制</li><li>准备好了？去配置工具：<a href="/deploy/claude-code">Claude Code</a> / <a href="/deploy/codex">Codex</a> / <a href="/apps/cherry-studio">Cherry Studio</a></li></ul>',26)])])}const f=d(n,[["render",l]]);export{k as __pageData,f as default};
